export async function generateMetadata({ params }: { params: Promise<{ username: string }> }) {
  const { username } = await params
  return { title: `@${username} · Forge` }
}

// ─── ACHIEVEMENT SYSTEM ───────────────────────────────────────────────────
// Earned from real stats — no fake badges
function getAchievements(projects: ProjectWithRelations[], totalStars: number, totalViews: number) {
  const list: Array<{ icon: string; label: string; desc: string }> = []
  if (projects.length >= 1)  list.push({ icon: '◫', label: 'Builder',        desc: 'First project published'   })
  if (projects.length >= 5)  list.push({ icon: '◈', label: 'Prolific',        desc: '5+ projects archived'      })
  if (projects.length >= 10) list.push({ icon: '◎', label: 'Top Contributor', desc: '10+ projects published'    })
  if (totalStars  >= 10)     list.push({ icon: '★', label: 'Acclaimed',       desc: '10+ stars earned'          })
  if (totalStars  >= 50)     list.push({ icon: '✦', label: 'Renowned',        desc: '50+ stars earned'          })
  if (totalViews  >= 100)    list.push({ icon: '◉', label: 'Discovered',      desc: '100+ profile views'        })
  if (totalViews  >= 1000)   list.push({ icon: '⌕', label: 'Influential',     desc: '1000+ project views'       })
  const hasBuildOn = projects.some(p => (p as any).build_ons_child?.length > 0 || (p as any).build_ons_parent?.length > 0)
  if (hasBuildOn)            list.push({ icon: '⊕', label: 'Chain Maker',     desc: 'Contributed to build-on lineage' })
  return list
}

// ─── CONTRIBUTION HEATMAP ─────────────────────────────────────────────────
// Built from real project/assignment submission dates
function buildHeatmap(projects: ProjectWithRelations[], assignments: AssignmentWithProfile[]) {
  const counts: Record<string, number> = {}
  const now = new Date()
  // Last 52 weeks
  for (let w = 51; w >= 0; w--) {
    for (let d = 0; d < 7; d++) {
      const date = new Date(now)
      date.setDate(date.getDate() - (w * 7 + d))
      const key = date.toISOString().slice(0, 10)
      counts[key] = 0
    }
  }
  projects.forEach(p => {
    const key = p.created_at?.slice(0, 10)
    if (key && key in counts) counts[key] = (counts[key] ?? 0) + 2
  })
  assignments.forEach(a => {
    const key = a.created_at?.slice(0, 10)
    if (key && key in counts) counts[key] = (counts[key] ?? 0) + 1
  })
  return counts
}

// ─── ACTIVITY TIMELINE ────────────────────────────────────────────────────
function buildTimeline(projects: ProjectWithRelations[], assignments: AssignmentWithProfile[]) {
  type Event = { date: string; icon: string; text: string; sub: string }
  const events: Event[] = []
  projects.forEach(p => events.push({
    date: p.created_at,
    icon: '◫',
    text: `Published ${p.title}`,
    sub: `${p.star_count} stars · ${p.views ?? 0} views`,
  }))
  assignments.forEach(a => events.push({
    date: a.created_at,
    icon: '☰',
    text: `Uploaded ${a.title}`,
    sub: `${a.subject} · ${a.semester}`,
  }))
  return events
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    .slice(0, 8)
}

// ─── RELATIVE TIME ────────────────────────────────────────────────────────
function timeAgo(date: string) {
  const diff = Date.now() - new Date(date).getTime()
  const days = Math.floor(diff / 86400000)
  if (days === 0) return 'Today'
  if (days === 1) return 'Yesterday'
  if (days < 7)  return `${days} days ago`
  if (days < 30) return `${Math.floor(days / 7)}w ago`
  if (days < 365) return `${Math.floor(days / 30)}mo ago`
  return `${Math.floor(days / 365)}y ago`
}

